// Registers local git merge drivers for generated files that conflict often:
//   - pnpm-lock.yaml: rebuilt from the merged manifests (merge-pnpm-lock.mjs).
//   - README.AUTOGEN.md: keep our copy (the docs pipeline regenerates them).
// Runs from the root package's postinstall on every `pnpm install`, so every
// clone gets the drivers without any manual setup.  Does nothing outside a git
// work tree (CI tarballs, Docker image builds) and never fails the install.

import { execFileSync } from "node:child_process";

function git(args) {
    execFileSync("git", args, { stdio: "ignore" });
}

// The merge attribute (pnpm-lock.yaml merge=pnpm-lock) lives in .gitattributes
// and ships with the repo; only the driver command is per-clone local config,
// so it is the one piece that has to be registered here.
const DRIVER = "node ts/tools/scripts/merge-pnpm-lock.mjs %O %A %B %P";

try {
    git(["rev-parse", "--is-inside-work-tree"]);
} catch {
    process.exit(0); // not a git checkout - nothing to register
}

try {
    git([
        "config",
        "merge.pnpm-lock.name",
        "Regenerate pnpm-lock.yaml on merge",
    ]);
    git(["config", "merge.pnpm-lock.driver", DRIVER]);

    // Autogenerated READMEs carry a commit-stamped footer, so every branch
    // regenerates a different last line and they conflict constantly.  Keep our
    // side on merge; `true` is git's documented "keep ours" driver, and the docs
    // pipeline regenerates the file afterward.
    git([
        "config",
        "merge.keep-ours.name",
        "Keep our copy (regenerated by the docs pipeline)",
    ]);
    git(["config", "merge.keep-ours.driver", "true"]);
} catch (err) {
    // A missing or locked git config must never break `pnpm install`.
    console.warn(
        `[setup-merge-driver] could not register driver: ${err.message}`,
    );
}
